revision.text:
.portal {
	border: solid #aaa 1px;
	padding: 0;
}
.portal .tleft {
	margin: 0.5em 1em 0.5em 0
}
.portal .tright {
	margin: 0.5em 0 0.5em 1em
}
.portal > ul {
	display: table;
	box-sizing: border-box;
	padding: 0.1em;
	max-width: 175px;
	background: #f9f9f9;
	font-size: 85%;
	line-height: 110%;
	font-style: italic;
	font-weight: bold;
}
.portal > ul > li {
	display: table-row;
}
.portal > ul > li > span:first-child {
	display: table-cell;
	padding: 0.2em;
	vertical-align: middle;
	text-align: center;
}
.portal > ul > li > span:last-child {
	display: table-cell;
	padding: 0.2em 0.2em 0.2em 0.3em;
	vertical-align: middle;
}

