}

/* {{pp-template}} */
.portalbox {
	padding: 0; /* Timeless adds padding */
	margin: 0.5em 0;
	display: table;
	box-sizing: border-box;
	max-width: 175px;
	list-style: none;
}

.portalborder {
	border: 1px solid var(--border-color-base, #a2a9b1);
	padding: 0.1em;
	background: var(--background-color-neutral-subtle, #f8f9fa);
}

.portalbox-entry {
	display: table-row;
	font-size: 85%;
	line-height: 110%;
	height: 1.9em; /* sets min height */
	font-style: italic;
	font-weight: bold;
}

.portalbox-image {
	display: table-cell;
	padding: 0.2em;
	vertical-align: middle;
	text-align: center;
}

.portalbox-link {
	display: table-cell;
	padding: 0.2em 0.2em 0.2em 0.3em;
	vertical-align: middle;
}

@media (min-width: 720px) {
	.portalleft {
		margin: 0.5em 1em 0.5em 0
	}

	.portalright {
		clear: right;
		float: right;
		margin: 0.5em 0 0.5em 1em
	}
}

